// Auto-generated report fonts (latin-subset TTFs, base64) for jsPDF embedding.
// Source: Google Fonts via google-webfonts-helper — Spectral 500, Archivo 400/700,
// JetBrains Mono 400/700. Registering these makes the report match the design exactly
// (otherwise jsPDF falls back to Times / Helvetica / Courier).
import type { jsPDF } from 'jspdf';

const SPECTRAL_500 = '';
const ARCHIVO_400 = '';
const ARCHIVO_700 = '';
const MONO_400 = '';
const MONO_700 = '';

let registered = false;

/** Embed Spectral / Archivo / JetBrains Mono into the doc's virtual file system. */
export function registerReportFonts(d: jsPDF): void {
  // Safe to call once per document; the VFS is per-document so we always register.
  d.addFileToVFS('Spectral-Medium.ttf', SPECTRAL_500);
  d.addFont('Spectral-Medium.ttf', 'Spectral', 'normal');
  d.addFileToVFS('Archivo-Regular.ttf', ARCHIVO_400);
  d.addFont('Archivo-Regular.ttf', 'Archivo', 'normal');
  d.addFileToVFS('Archivo-Bold.ttf', ARCHIVO_700);
  d.addFont('Archivo-Bold.ttf', 'Archivo', 'bold');
  d.addFileToVFS('JetBrainsMono-Regular.ttf', MONO_400);
  d.addFont('JetBrainsMono-Regular.ttf', 'JetBrainsMono', 'normal');
  d.addFileToVFS('JetBrainsMono-Bold.ttf', MONO_700);
  d.addFont('JetBrainsMono-Bold.ttf', 'JetBrainsMono', 'bold');
  registered = true;
}

export function reportFontsRegistered(): boolean { return registered; }
